}

import java.io.IOException;
import java.nio.file.*;
import java.util.List;

public class Main {
    public static void main(String[] args) throws IOException {
        Path path = Path.of("students.txt");

        // Write test data first:
        Files.write(path, List.of("Alice,90", "Bob,85", "Carol,92", "David,78", "Eve,88"));

        // Read all lines:
        List<String> lines = Files.readAllLines(path);
        System.out.println("Lines: " + lines.size());

        // Parse CSV and find highest score:
        int maxScore = Files.lines(path)
            .mapToInt(line -> Integer.parseInt(line.split(",")[1]))
            .max()
            .orElse(0);
        System.out.println("Highest score: " + maxScore);

        // Read as string:
        String content = Files.readString(path);
        System.out.println(content.contains("Carol"));
    }
}

instruction:
`BufferedReader` reads line by line, efficiently, for large files:

```java
try (BufferedReader reader = Files.newBufferedReader(path)) {
    String line;
    while ((line = reader.readLine()) != null) {
        // process line
    }
}
```

The try-with-resources ensures the reader is always closed.

