import java.io.*;
import java.nio.file.*;
import java.util.List;

public class Main {
    public static void main(String[] args) throws IOException {
        Path path = Path.of("log.txt");
        Files.write(path, List.of("INFO: Server started", "ERROR: Connection failed", "INFO: Request received", "ERROR: Timeout", "WARN: High memory"));

        int errors = 0;
        int total  = 0;

        try (BufferedReader reader = Files.newBufferedReader(path)) {
            String line;
            while ((line = reader.readLine()) != null) {
                total++;
                if (line.startsWith("ERROR")) errors++;
            }
        }  // reader auto-closed here

        System.out.println("Total lines: " + total);
        System.out.println("Errors: " + errors);
    }
}

import java.io.IOException;
import java.nio.file.*;
import java.util.List;

public class Main {
    public static void main(String[] args) throws IOException {
        Path dir  = Path.of("myapp", "data");
        Path file = dir.resolve("config.txt");

        // Create directory structure:
        Files.createDirectories(dir);
        System.out.println("Dir exists: " + Files.isDirectory(dir));

        // Write a file in the directory:
        Files.write(file, List.of("host=localhost", "port=8080"));
        System.out.println("File name: " + file.getFileName());
        System.out.println("Parent: " + file.getParent());

        // Cleanup:
        Files.delete(file);
        Files.delete(dir);
        Files.delete(dir.getParent());
        System.out.println("Cleaned up.");
    }
}
